actionConfiguration.body:
async function () {
  const member_id = selMember.selectedOptionValue;
  const release_type = selReleaseType.selectedOptionValue;
  if (!member_id) {
    showAlert("Select a member.", "warning");
    return;
  }
  await releaseFlows.auditLog("release.attempt", "member", member_id, {
    member_id,
    release_type,
    page: appsmith.URL?.pathname
  });
  const gate = await releaseFlows.refreshGate();
  const gateRow = gate?.[0];
  if (!gateRow?.member_agreement_id) {
    showAlert(`Not eligible. Member must sign the required agreement for: ${release_type}`, "error");
    return;
  }
  const product = tblProducts.selectedRow;
  if (release_type === "sacrament_release") {
    if (!product?.mushroomprocess_product_id) {
      showAlert("Select a product to issue.", "warning");
      return;
    }
  }
  const facilitator_id = selFacilitator.selectedOptionValue || null;
  if (!facilitator_id) {
    showAlert("Select a facilitator.", "warning");
    return;
  }
  const quantity = 1;
  if (!Number.isFinite(quantity) || quantity <= 0) {
    showAlert("Quantity must be a positive number.", "warning");
    return;
  }
  const unit = "g";
  const notes = inpNotes.text || null;
  if (release_type === "sacrament_release") {
    await apiMarkProductShipped.run();
  }
  showAlert(`Shipped: ${product?.mushroomprocess_product_id || "ok"}`, "success");
  const ins = await qCreateRelease.run({
    member_id: member_id,
    release_type: release_type,
    member_agreement_id: gateRow.member_agreement_id,
    mushroomprocess_product_id: product?.mushroomprocess_product_id || null,
    item_name: product?.item_name || release_type,
    quantity: quantity,
    unit: unit,
    net_weight_g: product?.net_weight_g.replace(/[a-zA-Z]+$/, "") || null,
    strain: product?.strain || null,
    facilitator_id: facilitator_id,
    notes: notes
  });
  showAlert(`Release issued: ${ins?.[0]?.sacrament_release_id || "ok"}`, "success");
  if (release_type === "sacrament_release") {
    await apiListAvailableProducts.run();
  }
  return ins;
}

