    }
const _agId = agRes?.[0]?.member_agreement_id || agRes?.member_agreement_id || agRes?.member_agreements_id || agRes?.[0]?.member_agreements_id || "";
			await this.auditLog("member_agreement.created","member_agreement", _agId, { member_id: memberId, facilitator_id: appsmith.store.selected_facilitator_id ?? "", signature_method: appsmith.store.signature_method ?? "", status: appsmith.store.agreement_status ?? "" });if (!uploadPaper) {

				showAlert("Digital release queued (pending email send).", "success");

				// 2) Normalize returned agreement id
				const agreementId =
					(typeof createRes === "string" && agRes) ||
					agRes?.member_agreement_id ||
					agRes?.[0]?.member_agreement_id ||
					agRes?.[0]?.member_agreements_id || // just in case naming differs
					null;

