				actor_email: ((appsmith.user?.email ?? "").trim().toLowerCase()),
				mode: appsmith.mode ?? "",
				details_json: JSON.stringify(payload ?? {}),
			});
		} catch (e) {
						console.log("audit_log insert failed:", e);
					}
	},

	async verifyaccess() {
		try {
			//showAlert("Beginning init. mode=" + appsmith.mode, "warning");

			// Wait briefly for Appsmith user context to hydrate
      let email = null;
      for (let i = 0; i < 20; i++) {
        email = (appsmith.user?.email ?? "").trim().toLowerCase();
        if (email) break;
        await new Promise(r => setTimeout(r, 150));
      }

			if (!email) {
				showAlert("Unknown user: appsmith.user.email not available.", "error");
				return;
			}

			// IMPORTANT: use return value of run(), not qCurrentFacilitator.data
      let rows = await qCurrentFacilitator.run({ email });

      // 🔴 Appsmith bug fix
      if (!Array.isArray(rows)) rows = [];
      //showAlert("qCurrentFacilitator rows=" + rows.length, "warning");

      const me = rows[0];	

			if (!me?.member_id) {
				showAlert("Access denied: not an active facilitator for " + email, "error");

				await this.auditLog("auth.denied","facilitator","", { email, page: appsmith.URL?.pathname, mode: appsmith.mode });if (appsmith.mode === "DEPLOYED" || appsmith.mode === "PUBLISHED") {
					//Only redirect when not in editor
					navigateTo("Unauthorized", {}, "SAME_WINDOW");
				}
				return;
			}

			const facilitator_id = me.member_id;
			const facilitator_email = (me.email ?? "").trim().toLowerCase();
			const is_document_reviewer = me.is_document_reviewer;

			//showAlert("Access granted for " + facilitator_email + " id=" + facilitator_id + " reviewer=" + is_document_reviewer, "success");

			// May want these enabled in deployed mode:
			storeValue("facilitator_id", facilitator_id);
			storeValue("facilitator_email", facilitator_email);
			storeValue("facilitator_is_reviewer", is_document_reviewer );
			storeValue("facilitator_full_name", `${me.first_name} ${me.last_name}`.trim());		


			//await this.auditLog("auth.granted","facilitator", facilitator_id, { email: facilitator_email, is_document_reviewer, page: appsmith.URL?.pathname, mode: appsmith.mode });
		} catch (e) {
			showAlert("Access check failed: " + (e?.message || e), "error");
			// Helpful: show query error if present
			showAlert("Query error: " + JSON.stringify(qCurrentFacilitator?.error ?? {}), "error");
			if (appsmith.mode === "DEPLOYED" || appsmith.mode === "PUBLISHED") {
				//Only redirect when not in editor
				navigateTo("Unauthorized", {}, "SAME_WINDOW");
			}
			return;
		}
	},

  async refreshGate() {
    if (!selMember.selectedOptionValue) {
			if(!appsmith.URL.queryParams.member_id ) {
				showAlert("Select a member first.", "warning");
				return null;
			}
			selMember.setSelectedOption(appsmith.URL.queryParams.member_id);

    }
    return await qGateCheckAgreement.run({
      member_id: selMember.selectedOptionValue,
      release_type: selReleaseType.selectedOptionValue,
    });
  },

  async issueRelease() {
    const member_id = selMember.selectedOptionValue;
    const release_type = selReleaseType.selectedOptionValue;

    if (!member_id) {
      showAlert("Select a member.", "warning");
      return;
    }


    await this.auditLog("release.attempt","member", member_id, { member_id, release_type, page: appsmith.URL?.pathname });// Gate: enforce the right agreement type
    const gate = await this.refreshGate();
    const gateRow = gate?.[0];
    if (!gateRow?.member_agreement_id) {
      showAlert(`Not eligible. Member must sign the required agreement for: ${release_type}`, "error");
      return;
    }

    // Product selection required (for sacrament_release only)
    const product = tblProducts.selectedRow;
    if (release_type === "sacrament_release") {
      if (!product?.mushroomprocess_product_id) {
        showAlert("Select a product to issue.", "warning");
        return;
      }
    }

    const facilitator_id = selFacilitator.selectedOptionValue || null;
    if (!facilitator_id) {
      showAlert("Select a facilitator.", "warning");
      return;
    }

    //const quantity = Number(inpQuantity.text || 1);
		const quantity = 1;
    if (!Number.isFinite(quantity) || quantity <= 0) {
      showAlert("Quantity must be a positive number.", "warning");
      return;
    }


    //const unit = selUnit.selectedOptionValue || "unit";
		const unit = "g";
    const notes = inpNotes.text || null;

    // 1) Mark shipped in Airtable (only if sacrament_release)
    if (release_type === "sacrament_release") {
      await apiMarkProductShipped.run();
    }

		showAlert(`Shipped: ${product?.mushroomprocess_product_id || "ok"}`, "success");

    // 2) Insert release record in SignatureGate
    const ins = await qCreateRelease.run({
      member_id: member_id,
      release_type: release_type,
      member_agreement_id: gateRow.member_agreement_id,
      mushroomprocess_product_id: product?.mushroomprocess_product_id || null,
      item_name: product?.item_name || release_type,
      quantity: quantity,
      unit: unit,
      net_weight_g: product?.net_weight_g.replace(/[a-zA-Z]+$/, "") || null,
      strain: product?.strain || null,
      facilitator_id: facilitator_id,
      notes: notes,
    });

    showAlert(`Release issued: ${ins?.[0]?.sacrament_release_id || "ok"}`, "success");

    // Refresh products list so shipped disappears
    if (release_type === "sacrament_release") {
      await apiListAvailableProducts.run();
    }

    return ins;
  },
};

